)

// TestResendInviteCodeMembershipNotfound reproduces the bug where resend invite code
// returns "membership not found" error in login v1
func TestResendInviteCodeMembershipNotfound(t *testing.T) {
	// Setup test context with user context but no organization membership
	ctx := context.Background()
	userID := "test-user-123"

	// Create context with user data but no org membership (simulating login v1 scenario)
	ctxData := authz.CtxData{
		UserID: userID,
		OrgID:  "", // Empty org ID - this is the key issue!
	}
	ctx = authz.SetCtxData(ctx, ctxData)

	// Setup mock eventstore
	mockEventstore := &eventstore.Eventstore{}

	// Create commands instance
	cmds := &command.Commands{
		Eventstore: mockEventstore,
	}

	// Try to resend invite code - this should fail with membership not found
	_, err := cmds.ResendInviteCode(ctx, userID, "", "test-auth-request")

	// The bug manifests as a "membership not found" error
	// We expect this to fail, but the actual error might be different
	fmt.Printf("Error: %v\n", err)

	// The key issue is that when userOrgID is empty in the login v1 context,
	// the permission check fails because it can't find the user's membership
	assert.Error(t, err, "ResendInviteCode should fail with membership not found error")
}

func main() {
	// Run a simple test to demonstrate the issue
	t := &testing.T{}
	TestResendInviteCodeMembershipNotfound(t)
	fmt.Println("Test completed")
}

